/**
 * Enqueue a notification for ordered delivery.
 * Notifications for the same user/recipient are delivered sequentially
 * to prevent out-of-order arrival (e.g., "payment confirmed" before "order placed").
 */
private async sendNotification(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  userId?: string;
  subject: string;
  body: string;
  metadata?: Record<string, string>;
}): Promise<NotificationResult> {
  const queueKey = params.userId ?? params.recipient;
  const previous = this.deliveryQueues.get(queueKey) ?? Promise.resolve();

  const resultPromise = previous.then(
    () => this.dispatchNotification(params),
    () => this.dispatchNotification(params),
  );

  // Store the chain so the next notification waits for this one
  this.deliveryQueues.set(queueKey, resultPromise);

  return resultPromise;
}

